#include <stdio.h>
#include <stdlib.h>

typedef struct Node {int v; struct Node* next;} Node;

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N,M; scanf("%d %d", &N, &M);
        Node** adj = (Node**)calloc(N+1, sizeof(Node*));
        for(int i=0;i<M;i++){
            int u,v; scanf("%d %d", &u, &v);
            Node* a = (Node*)malloc(sizeof(Node)); a->v=v; a->next=adj[u]; adj[u]=a;
            Node* b = (Node*)malloc(sizeof(Node)); b->v=u; b->next=adj[v]; adj[v]=b;
        }
        int* color = (int*)malloc((N+1)*sizeof(int));
        for(int i=1;i<=N;i++) color[i] = -1;
        int ok = 1;
        int* queue = (int*)malloc((N+5)*sizeof(int));
        for(int start=1; start<=N && ok; ++start){
            if(color[start]!=-1) continue;
            int head=0, tail=0;
            queue[tail++] = start; color[start]=0;
            while(head<tail && ok){
                int u = queue[head++];
                for(Node* p=adj[u]; p; p=p->next){
                    int v = p->v;
                    if(color[v]==-1){
                        color[v]=color[u]^1;
                        queue[tail++] = v;
                    }else if(color[v]==color[u]){
                        ok=0; break;
                    }
                }
            }
        }
        printf(ok?"YES\n":"NO\n");
        // free memory
        for(int i=1;i<=N;i++){
            Node* p=adj[i];
            while(p){ Node* tmp=p; p=p->next; free(tmp);} }
        free(adj); free(color); free(queue);
    }
    return 0;
}

